function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const adj = new Array(n).fill(0).map(() => []);
    for (const [u, v, cost] of edges) {
        adj[u].push({ to: v, cost });
    }

    class PriorityQueue {
        private heap: [number, number, number][];
        constructor() {
            this.heap = [];
        }
        push(value: [number, number, number]) {
            this.heap.push(value);
            this.heapifyUp(this.heap.length - 1);
        }
        pop(): [number, number, number] | null {
            if (this.heap.length === 0) return null;
            const result = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            this.heapifyDown(0);
            return result;
        }
        private heapifyUp(index: number) {
            let parent = Math.floor((index - 1) / 2);
            while (index > 0 && this.heap[index][0] < this.heap[parent][0]) {
                [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
                index = parent;
                parent = Math.floor((index - 1) / 2);
            }
        }
        private heapifyDown(index: number) {
            let smallest = index;
            const left = 2 * index + 1;
            const right = 2 * index + 2;
            if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }
            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                this.heapifyDown(smallest);
            }
        }
    }

    const pq = new PriorityQueue();
    pq.push([0, 0, 0]);
    const best_min = new Array(n).fill(-Infinity);
    best_min[0] = 0;

    while (pq.heap.length > 0) {
        const [current_min_neg, total_cost, node] = pq.pop()!;
        const current_min = -current_min_neg;

        if (node === n - 1) {
            return current_min;
        }

        if (current_min < best_min[node]) {
            continue;
        }

        for (const edge of adj[node]) {
            const v = edge.to;
            const cost = edge.cost;

            if (!online[v]) {
                continue;
            }

            const new_total = total_cost + cost;
            if (new_total > k) {
                continue;
            }

            const new_min = Math.min(current_min, cost);

            if (new_min > best_min[v]) {
                best_min[v] = new_min;
                pq.push([-new_min, new_total, v]);
            }
        }
    }

    return -1;
}
